import React, {useState} from 'react';

function Projects({name, desc}){
  const [isprojects, setProjects] = useState([
    {
      id: 1,
      name: "Booklandia",
      desc: "Website",
      img: "img/works/booklandia-site.png",
    },
    {
      id: 2,
      name: "TESDA Women's Center",
      desc: "Website",
      img: "img/works/twc.png",
    },
    {
      id: 3,
      name: "Booklandia",
      desc: "Website",
      img: "img/works/fun-run.png",
    },
  ])

  return(
    <div>
    {isprojects.map(project => (
      <a className="works-item smooth-leave" href="booklandia.html">
        <div className="picture">
          <div className="content">
            <div className="text">
              <h2>{project.name}</h2>
              <ul>
                <li>{project.desc}</li>
              </ul>
            </div>
          </div>
          <img src="img/works/booklandia.png" alt="" />
        </div>
      </a>
    ))}
    </div>
  );
}
export default Projects
